# JavaScript Debounce 函数

Debounce（防抖）的核心思想是：**在连续触发的事件中，只在最后一次触发后等待指定时间再执行回调**。常用于搜索输入、窗口 resize、滚动加载等场景。

## 标准实现

```javascript
/**
 * 创建一个 debounce（防抖）函数
 * @param {Function} fn       - 要执行的回调函数
 * @param {number}   delay    - 延迟时间（毫秒）
 * @param {Object}   options  - 可选配置
 * @param {boolean}  options.leading  - 是否在延迟开始前立即执行一次（默认 false）
 * @param {boolean}  options.trailing - 是否在延迟结束后执行（默认 true）
 * @returns {Function} 返回防抖后的函数
 */
function debounce(fn, delay, options = {}) {
  const { leading = false, trailing = true } = options;
  let timer = null;
  let lastArgs = null;
  let isInvoked = false; // leading 调用标记

  const debounced = function (...args) {
    // 如果 trailing 为 false 且没有定时器在跑，直接返回
    if (!trailing && !leading) return;

    lastArgs = args;

    // 清除上次的定时器
    if (timer) {
      clearTimeout(timer);
      timer = null;
    }

    // leading：立即执行一次
    if (leading && !isInvoked) {
      isInvoked = true;
      fn.apply(this, args);
    }

    // trailing：延迟结束后执行
    if (trailing) {
      timer = setTimeout(() => {
        isInvoked = false;
        timer = null;
        // 如果是 leading 模式且已经执行过，这次不再重复执行
        if (!leading) {
          fn.apply(this, lastArgs);
        }
        lastArgs = null;
      }, delay);
    }
  };

  /**
   * 取消防抖，立即取消待执行的调用
   */
  debounced.cancel = function () {
    if (timer) {
      clearTimeout(timer);
      timer = null;
    }
    isInvoked = false;
    lastArgs = null;
  };

  /**
   * 立即执行 pending 中的调用
   */
  debounced.flush = function () {
    if (timer && lastArgs) {
      clearTimeout(timer);
      timer = null;
      fn.apply(this, lastArgs);
      lastArgs = null;
      isInvoked = false;
    }
  };

  return debounced;
}
```

## 使用示例

```javascript
// 基础用法：输入框搜索（trailing 模式）
const searchInput = document.getElementById('search');
const handleSearch = debounce((e) => {
  console.log('发起搜索请求:', e.target.value);
}, 500);
searchInput.addEventListener('input', handleSearch);

// leading 模式：提交按钮防抖（立即执行，防止重复提交）
const submitBtn = document.getElementById('submit');
const handleSubmit = debounce(
  () => console.log('提交表单'),
  1000,
  { leading: true, trailing: false }
);
submitBtn.addEventListener('click', handleSubmit);

// 使用 cancel / flush
const log = debounce(() => console.log('hello'), 2000);
log();
log.cancel();          // 取消未执行的调用
log.flush();           // 立即执行 pending 中的调用
```

## 精简版（日常够用）

```javascript
function debounce(fn, delay) {
  let timer;
  return function (...args) {
    clearTimeout(timer);
    timer = setTimeout(() => fn.apply(this, args), delay);
  };
}
```

## 核心要点

| 配置 | 行为 | 典型场景 |
|------|------|----------|
| `leading: false, trailing: true`（默认） | 最后一次触发后延迟执行 | 搜索输入、自动保存 |
| `leading: true, trailing: false` | 第一次触发立即执行，后续忽略 | 提交按钮防重复点击 |
| `leading: true, trailing: true` | 第一次立即执行，最后一次也执行 | 某些轮询场景 |

